import React from 'react';
import './Species.css';

const species = [
  {
    name: 'Peacock Bass',
    latin: 'Cichla temensis',
    img: '/images/species/peacock-bass.jpg',
    desc: "The most aggressive freshwater predator. Explosive topwater strikes. Capt Drew's personal best: 22 lbs on the Urubaxi.",
    stars: 4,
    diff: 'Moderate',
  },
  {
    name: 'Everglades Largemouth Bass',
    latin: 'Micropterus salmoides floridanus',
    img: '/images/species/Everglades Largemouth Bass.jpg',
    desc: "Apex predator of South Florida's canals. Explosive topwater strikes and aggressive runs. Drew's personal best is over 10 lbs — a true Florida trophy.",
    stars: 4,
    diff: 'Intermediate',
  },
  {
    name: 'Butterfly Peacock Bass',
    latin: 'Cichla ocellaris',
    img: '/images/gallery/catch-3.jpg',
    desc: "Smaller cousin of the Giant Peacock — but pound-for-pound just as aggressive. Drew's clients land them year-round in Miami's canals.",
    stars: 4,
    diff: 'All Levels',
  },
  {
    name: 'Popoca',
    latin: 'Cichla monoculus',
    img: '/images/species/Popoca.jpg',
    desc: "The Amazon's freshwater barracuda. Blindingly fast ambush predator that strikes surface lures with savage ferocity.",
    stars: 3,
    diff: 'Intermediate',
  },
];

export default function Species() {
  return (
    <section id="species" className="species">
      <div className="species-header">
        <div>
          <div className="section-tag-line">Target Species</div>
          <h2 className="section-title">
            The Fish You'll <em>Chase</em>
          </h2>
        </div>
        <a href="#contact" className="btn-gold-sm">
          Plan Your Trip
        </a>
      </div>

      <div className="species-grid">
        {species.map(s => (
          <div className="species-card" key={s.name}>

            {/* PHOTO */}
            <div className="species-img-wrap">
              <img
                src={s.img}
                alt={s.name}
                className="species-img"
                onError={e => {
                  e.target.style.display = 'none';
                  e.target.parentNode.style.background = '#0F6E56';
                }}
              />
              <div className="species-img-overlay" />
            </div>

            {/* INFO */}
            <div className="species-info">
              <div className="species-name">{s.name}</div>
              <div className="species-latin">{s.latin}</div>
              <div className="species-desc">{s.desc}</div>
              <div className="species-rating">
                <span className="stars">
                  {'★'.repeat(s.stars)}{'☆'.repeat(5 - s.stars)}
                </span>
                <span className="diff">Difficulty: {s.diff}</span>
              </div>
            </div>

          </div>
        ))}
      </div>
    </section>
  );
}
